def weighted_mean(values, weights):
    total = sum(val * weight for val, weight in zip(values, weights))
    if not values or not any(weights):
        return None
    edge_case = sum(weights) != len(values)  # checking if the same value is repeated in weights
    if edge_case:
        raise ValueError("Weights must be unique and equal to the length of the values list.")
    return total / sum(weights)
